-- ============================================================
-- Smart Pocket — FAQ Module
-- Migration: 20260626170000_faqs_module.sql
-- ============================================================

BEGIN;

CREATE TABLE IF NOT EXISTS public.faq_categories (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  slug TEXT NOT NULL UNIQUE,
  icon TEXT,
  sort_order INTEGER NOT NULL DEFAULT 0,
  is_active BOOLEAN NOT NULL DEFAULT true,
  created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
  CONSTRAINT faq_categories_slug_format_check CHECK (slug ~ '^[a-z0-9]+(?:-[a-z0-9]+)*$')
);

CREATE TABLE IF NOT EXISTS public.faq_category_translations (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  category_id UUID NOT NULL REFERENCES public.faq_categories(id) ON DELETE CASCADE,
  language_code TEXT NOT NULL,
  name TEXT NOT NULL DEFAULT '',
  description TEXT NOT NULL DEFAULT '',
  created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
  CONSTRAINT faq_category_translations_unique UNIQUE (category_id, language_code),
  CONSTRAINT faq_category_translations_language_check CHECK (language_code IN ('en', 'ar', 'fr', 'ru'))
);

CREATE TABLE IF NOT EXISTS public.faq_items (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  category_id UUID NOT NULL REFERENCES public.faq_categories(id) ON DELETE CASCADE,
  slug TEXT NOT NULL UNIQUE,
  sort_order INTEGER NOT NULL DEFAULT 0,
  is_active BOOLEAN NOT NULL DEFAULT true,
  is_featured BOOLEAN NOT NULL DEFAULT false,
  created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
  CONSTRAINT faq_items_slug_format_check CHECK (slug ~ '^[a-z0-9]+(?:-[a-z0-9]+)*$')
);

CREATE TABLE IF NOT EXISTS public.faq_item_translations (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  item_id UUID NOT NULL REFERENCES public.faq_items(id) ON DELETE CASCADE,
  language_code TEXT NOT NULL,
  question TEXT NOT NULL DEFAULT '',
  answer_html TEXT NOT NULL DEFAULT '',
  keywords TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[],
  created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
  CONSTRAINT faq_item_translations_unique UNIQUE (item_id, language_code),
  CONSTRAINT faq_item_translations_language_check CHECK (language_code IN ('en', 'ar', 'fr', 'ru'))
);

CREATE INDEX IF NOT EXISTS idx_faq_categories_active_order ON public.faq_categories (is_active, sort_order, created_at);
CREATE INDEX IF NOT EXISTS idx_faq_items_category_active_order ON public.faq_items (category_id, is_active, sort_order, created_at);
CREATE INDEX IF NOT EXISTS idx_faq_items_active_order ON public.faq_items (is_active, sort_order, created_at);

DROP TRIGGER IF EXISTS update_faq_categories_updated_at ON public.faq_categories;
CREATE TRIGGER update_faq_categories_updated_at
  BEFORE UPDATE ON public.faq_categories
  FOR EACH ROW
  EXECUTE FUNCTION public.set_updated_at();

DROP TRIGGER IF EXISTS update_faq_category_translations_updated_at ON public.faq_category_translations;
CREATE TRIGGER update_faq_category_translations_updated_at
  BEFORE UPDATE ON public.faq_category_translations
  FOR EACH ROW
  EXECUTE FUNCTION public.set_updated_at();

DROP TRIGGER IF EXISTS update_faq_items_updated_at ON public.faq_items;
CREATE TRIGGER update_faq_items_updated_at
  BEFORE UPDATE ON public.faq_items
  FOR EACH ROW
  EXECUTE FUNCTION public.set_updated_at();

DROP TRIGGER IF EXISTS update_faq_item_translations_updated_at ON public.faq_item_translations;
CREATE TRIGGER update_faq_item_translations_updated_at
  BEFORE UPDATE ON public.faq_item_translations
  FOR EACH ROW
  EXECUTE FUNCTION public.set_updated_at();

ALTER TABLE public.faq_categories ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.faq_category_translations ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.faq_items ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.faq_item_translations ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS faq_categories_public_read ON public.faq_categories;
CREATE POLICY faq_categories_public_read
ON public.faq_categories
FOR SELECT
TO public
USING (is_active = true);

DROP POLICY IF EXISTS faq_category_translations_public_read ON public.faq_category_translations;
CREATE POLICY faq_category_translations_public_read
ON public.faq_category_translations
FOR SELECT
TO public
USING (
  EXISTS (
    SELECT 1
    FROM public.faq_categories c
    WHERE c.id = faq_category_translations.category_id
      AND c.is_active = true
  )
);

DROP POLICY IF EXISTS faq_items_public_read ON public.faq_items;
CREATE POLICY faq_items_public_read
ON public.faq_items
FOR SELECT
TO public
USING (
  is_active = true
  AND EXISTS (
    SELECT 1
    FROM public.faq_categories c
    WHERE c.id = faq_items.category_id
      AND c.is_active = true
  )
);

DROP POLICY IF EXISTS faq_item_translations_public_read ON public.faq_item_translations;
CREATE POLICY faq_item_translations_public_read
ON public.faq_item_translations
FOR SELECT
TO public
USING (
  EXISTS (
    SELECT 1
    FROM public.faq_items i
    JOIN public.faq_categories c ON c.id = i.category_id
    WHERE i.id = faq_item_translations.item_id
      AND i.is_active = true
      AND c.is_active = true
  )
);

DROP POLICY IF EXISTS faq_categories_admin_manage ON public.faq_categories;
CREATE POLICY faq_categories_admin_manage
ON public.faq_categories
FOR ALL
TO authenticated
USING (public.is_admin())
WITH CHECK (public.is_admin());

DROP POLICY IF EXISTS faq_category_translations_admin_manage ON public.faq_category_translations;
CREATE POLICY faq_category_translations_admin_manage
ON public.faq_category_translations
FOR ALL
TO authenticated
USING (public.is_admin())
WITH CHECK (public.is_admin());

DROP POLICY IF EXISTS faq_items_admin_manage ON public.faq_items;
CREATE POLICY faq_items_admin_manage
ON public.faq_items
FOR ALL
TO authenticated
USING (public.is_admin())
WITH CHECK (public.is_admin());

DROP POLICY IF EXISTS faq_item_translations_admin_manage ON public.faq_item_translations;
CREATE POLICY faq_item_translations_admin_manage
ON public.faq_item_translations
FOR ALL
TO authenticated
USING (public.is_admin())
WITH CHECK (public.is_admin());

