GRANT SELECT ON TABLE public.faq_category_translations TO anon, authenticated, service_role;
GRANT SELECT ON TABLE public.faq_items TO anon, authenticated, service_role;
GRANT SELECT ON TABLE public.faq_item_translations TO anon, authenticated, service_role;
GRANT INSERT, UPDATE, DELETE ON TABLE public.faq_categories TO authenticated, service_role;
GRANT INSERT, UPDATE, DELETE ON TABLE public.faq_category_translations TO authenticated, service_role;
GRANT INSERT, UPDATE, DELETE ON TABLE public.faq_items TO authenticated, service_role;
GRANT INSERT, UPDATE, DELETE ON TABLE public.faq_item_translations TO authenticated, service_role;

