INSERT INTO public.faq_categories (slug, icon, sort_order, is_active)
SELECT
  entry ->> 'slug',
  NULLIF(entry ->> 'icon', ''),
  COALESCE((entry ->> 'sort_order')::INTEGER, 0),
  true
FROM category_seed
CROSS JOIN LATERAL jsonb_array_elements(category_seed.data) AS entry
ON CONFLICT (slug) DO UPDATE
SET icon = EXCLUDED.icon,
    sort_order = EXCLUDED.sort_order,
    is_active = EXCLUDED.is_active;

