INSERT INTO public.faq_category_translations (category_id, language_code, name, description)
SELECT
  c.id,
  tr.key,
  COALESCE(tr.value ->> 'name', ''),
  COALESCE(tr.value ->> 'description', '')
FROM category_seed
CROSS JOIN LATERAL jsonb_array_elements(category_seed.data) AS entry
CROSS JOIN LATERAL jsonb_each(entry -> 'translations') AS tr(key, value)
JOIN public.faq_categories c ON c.slug = entry ->> 'slug'
ON CONFLICT (category_id, language_code) DO UPDATE
SET name = EXCLUDED.name,
    description = EXCLUDED.description;

WITH item_seed AS (
  SELECT '[{"category_slug": "getting-started", "slug": "what-is-smart-pocket", "sort_order": 10, "is_featured": true, "translations": {"en": {"question": "What is Smart Pocket?", "answer_html": "<p>Smart Pocket is a personal finance app for tracking accounts, transactions, budgets, recurring activity, reimbursements, and reports in one place.</p>", "keywords": ["smart pocket", "finance app", "money tracking"]}, "ar": {"question": "ما هو Smart Pocket؟", "answer_html": "<p>Smart Pocket هو تطبيق لإدارة المال الشخصي يساعدك على تتبع الحسابات والمعاملات والميزانيات والعمليات المتكررة والمبالغ المستردة والتقارير في مكان واحد.</p>", "keywords": ["سمارت بوكيت", "تطبيق مالي", "تتبع الأموال"]}, "fr": {"question": "Qu''est-ce que Smart Pocket ?", "answer_html": "<p>Smart Pocket est une application de finance personnelle qui centralise comptes, transactions, budgets, opérations récurrentes, remboursements et rapports.</p>", "keywords": ["smart pocket", "application finance", "suivi argent"]}, "ru": {"question": "Что такое Smart Pocket?", "answer_html": "<p>Smart Pocket — это приложение для личных финансов, где можно вести счета, транзакции, бюджеты, регулярные операции, возмещения и отчеты в одном месте.</p>", "keywords": ["smart pocket", "финансовое приложение", "учет денег"]}}}, {"category_slug": "getting-started", "slug": "what-should-i-configure-first", "sort_order": 20, "translations": {"en": {"question": "What should I configure first?", "answer_html": "<p>Start with your profile, default currency, and the default Cash and Bank accounts, then record your first transaction so balances and reports begin with useful data.</p>", "keywords": ["profile", "default currency", "cash bank"]}, "ar": {"question": "ما الذي يجب أن أعدّه أولاً؟", "answer_html": "<p>ابدأ بملفك الشخصي والعملة الافتراضية وحسابي Cash وBank الافتراضيين، ثم سجّل أول معاملة حتى تبدأ الأرصدة والتقارير ببيانات مفيدة.</p>", "keywords": ["الملف الشخصي", "العملة الافتراضية", "النقد والبنك"]}, "fr": {"question": "Que dois-je configurer en premier ?", "answer_html": "<p>Commencez par votre profil, votre devise par défaut et les comptes Cash et Bank par défaut, puis enregistrez votre première transaction pour alimenter les soldes et rapports.</p>", "keywords": ["profil", "devise par défaut", "cash bank"]}, "ru": {"question": "Что настроить в первую очередь?", "answer_html": "<p>Сначала заполните профиль, валюту по умолчанию и стандартные счета Cash и Bank, а затем внесите первую транзакцию, чтобы балансы и отчеты стали полезными.</p>", "keywords": ["профиль", "валюта по умолчанию", "cash bank"]}}}, {"category_slug": "ai-smart-entry", "slug": "what-is-smart-entry", "sort_order": 10, "is_featured": true, "translations": {"en": {"question": "What is Smart Entry?", "answer_html": "<p>Smart Entry lets you describe one or more financial actions in natural language and turns them into draft records for review before saving.</p>", "keywords": ["smart entry", "ai", "drafts"]}, "ar": {"question": "ما هو الإدخال الذكي؟", "answer_html": "<p>يتيح لك الإدخال الذكي وصف إجراء مالي واحد أو عدة إجراءات بلغة طبيعية ثم يحولها إلى مسودات جاهزة للمراجعة قبل الحفظ.</p>", "keywords": ["الإدخال الذكي", "ذكاء اصطناعي", "مسودات"]}, "fr": {"question": "Qu''est-ce que Smart Entry ?", "answer_html": "<p>Smart Entry vous permet de décrire une ou plusieurs actions financières en langage naturel et les transforme en brouillons à vérifier avant l''enregistrement.</p>", "keywords": ["smart entry", "ia", "brouillons"]}, "ru": {"question": "Что такое Smart Entry?", "answer_html": "<p>Smart Entry позволяет описать одно или несколько финансовых действий обычным языком и превращает их в черновики для проверки перед сохранением.</p>", "keywords": ["smart entry", "ии", "черновики"]}}}, {"category_slug": "ai-smart-entry", "slug": "why-must-i-review-ai-results-before-saving", "sort_order": 20, "translations": {"en": {"question": "Why must I review AI results before saving?", "answer_html": "<p>AI suggestions are drafts, not final records. Review them to confirm amounts, dates, categories, accounts, and direction before anything is saved.</p>", "keywords": ["review ai", "confirm", "before saving"]}, "ar": {"question": "لماذا يجب أن أراجع نتائج الذكاء الاصطناعي قبل الحفظ؟", "answer_html": "<p>اقتراحات الذكاء الاصطناعي هي مسودات وليست سجلات نهائية. راجعها للتأكد من المبالغ والتواريخ والفئات والحسابات والاتجاه قبل الحفظ.</p>", "keywords": ["مراجعة الذكاء الاصطناعي", "التأكيد", "قبل الحفظ"]}, "fr": {"question": "Pourquoi faut-il vérifier les résultats de l''IA avant d''enregistrer ?", "answer_html": "<p>Les suggestions de l''IA sont des brouillons, pas des écritures finales. Vérifiez montants, dates, catégories, comptes et sens avant l''enregistrement.</p>", "keywords": ["vérifier ia", "confirmer", "avant enregistrement"]}, "ru": {"question": "Почему нужно проверять результаты ИИ перед сохранением?", "answer_html": "<p>Подсказки ИИ — это черновики, а не окончательные записи. Проверьте суммы, даты, категории, счета и направление операции до сохранения.</p>", "keywords": ["проверка ии", "подтвердить", "до сохранения"]}}}, {"category_slug": "transactions", "slug": "how-do-i-add-an-expense", "sort_order": 10, "translations": {"en": {"question": "How do I add an expense?", "answer_html": "<p>Open Add Transaction, choose Expense, select the account to pay from, then enter the amount, category, date, and notes.</p>", "keywords": ["expense", "add transaction", "pay from"]}, "ar": {"question": "كيف أضيف مصروفاً؟", "answer_html": "<p>افتح إضافة معاملة، واختر Expense، وحدد الحساب الذي ستدفع منه، ثم أدخل المبلغ والفئة والتاريخ والملاحظات.</p>", "keywords": ["مصروف", "إضافة معاملة", "الدفع من"]}, "fr": {"question": "Comment ajouter une dépense ?", "answer_html": "<p>Ouvrez Ajouter une transaction, choisissez Expense, sélectionnez le compte à débiter, puis saisissez le montant, la catégorie, la date et les notes.</p>", "keywords": ["dépense", "ajouter transaction", "payer depuis"]}, "ru": {"question": "Как добавить расход?", "answer_html": "<p>Откройте добавление транзакции, выберите Expense, укажите счет списания, затем введите сумму, категорию, дату и заметки.</p>", "keywords": ["расход", "добавить транзакцию", "оплатить со счета"]}}}, {"category_slug": "transactions", "slug": "how-are-categories-used", "sort_order": 20, "translations": {"en": {"question": "How are categories used?", "answer_html": "<p>Categories organize spending and income for reports, filters, and budgets. Use Groceries & Household for supermarket and home essentials, and Dining Out for restaurants, cafes, and takeout.</p>", "keywords": ["categories", "groceries household", "dining out"]}, "ar": {"question": "كيف تُستخدم الفئات؟", "answer_html": "<p>تنظم الفئات المصروفات والدخل داخل التقارير والفلاتر والميزانيات. استخدم Groceries & Household لمشتريات السوبرماركت ولوازم المنزل، وDining Out للمطاعم والمقاهي والطلبات الخارجية.</p>", "keywords": ["الفئات", "مشتريات المنزل", "تناول الطعام خارج المنزل"]}, "fr": {"question": "Comment les catégories sont-elles utilisées ?", "answer_html": "<p>Les catégories organisent dépenses et revenus dans les rapports, filtres et budgets. Utilisez Groceries & Household pour le supermarché et la maison, et Dining Out pour restaurants, cafés et plats à emporter.</p>", "keywords": ["catégories", "courses maison", "repas à l''extérieur"]}, "ru": {"question": "Как используются категории?", "answer_html": "<p>Категории помогают упорядочивать расходы и доходы в отчетах, фильтрах и бюджетах. Используйте Groceries & Household для супермаркета и товаров для дома, а Dining Out — для ресторанов, кафе и доставки.</p>", "keywords": ["категории", "продукты и дом", "еда вне дома"]}}}, {"category_slug": "accounts", "slug": "what-is-a-financial-account", "sort_order": 10, "translations": {"en": {"question": "What is a financial account?", "answer_html": "<p>A financial account is any place where money is stored, spent from, or received into, such as cash, a bank account, or another tracked account.</p>", "keywords": ["financial account", "cash", "bank"]}, "ar": {"question": "ما هو الحساب المالي؟", "answer_html": "<p>الحساب المالي هو أي مكان تُحفظ فيه الأموال أو تُنفق منه أو تُستلم فيه، مثل النقد أو الحساب البنكي أو أي حساب آخر تتم متابعته.</p>", "keywords": ["حساب مالي", "نقد", "بنك"]}, "fr": {"question": "Qu''est-ce qu''un compte financier ?", "answer_html": "<p>Un compte financier est tout endroit où l''argent est conservé, dépensé ou reçu, comme du cash, un compte bancaire ou tout autre compte suivi.</p>", "keywords": ["compte financier", "cash", "banque"]}, "ru": {"question": "Что такое финансовый счет?", "answer_html": "<p>Финансовый счет — это любое место, где хранятся деньги, откуда они тратятся или куда поступают: наличные, банковский счет или другой отслеживаемый счет.</p>", "keywords": ["финансовый счет", "наличные", "банк"]}}}, {"category_slug": "accounts", "slug": "how-do-transfers-between-accounts-work", "sort_order": 20, "translations": {"en": {"question": "How do transfers between accounts work?", "answer_html": "<p>A transfer moves money from one financial account to another without treating it as new income or a new expense.</p>", "keywords": ["transfer", "between accounts", "move money"]}, "ar": {"question": "كيف تعمل التحويلات بين الحسابات؟", "answer_html": "<p>يقوم التحويل بنقل المال من حساب مالي إلى آخر دون اعتباره دخلاً جديداً أو مصروفاً جديداً.</p>", "keywords": ["تحويل", "بين الحسابات", "نقل المال"]}, "fr": {"question": "Comment fonctionnent les transferts entre comptes ?", "answer_html": "<p>Un transfert déplace l''argent d''un compte financier vers un autre sans le considérer comme un nouveau revenu ou une nouvelle dépense.</p>", "keywords": ["transfert", "entre comptes", "déplacer argent"]}, "ru": {"question": "Как работают переводы между счетами?", "answer_html": "<p>Перевод перемещает деньги с одного финансового счета на другой и не считается новым доходом или расходом.</p>", "keywords": ["перевод", "между счетами", "переместить деньги"]}}}, {"category_slug": "personal-subscriptions", "slug": "what-is-a-personal-subscription", "sort_order": 10, "is_featured": true, "translations": {"en": {"question": "What is a Personal Subscription?", "answer_html": "<p>A Personal Subscription tracks a service or membership you personally pay for, such as Netflix, ChatGPT, a gym membership, or software.</p>", "keywords": ["personal subscription", "membership", "service"]}, "ar": {"question": "ما هو الاشتراك الشخصي؟", "answer_html": "<p>الاشتراك الشخصي يتتبع خدمة أو عضوية تدفعها أنت شخصياً، مثل Netflix أو ChatGPT أو عضوية النادي أو البرامج.</p>", "keywords": ["اشتراك شخصي", "عضوية", "خدمة"]}, "fr": {"question": "Qu''est-ce qu''un abonnement personnel ?", "answer_html": "<p>Un abonnement personnel suit un service ou une adhésion que vous payez personnellement, comme Netflix, ChatGPT, un abonnement de sport ou un logiciel.</p>", "keywords": ["abonnement personnel", "adhésion", "service"]}, "ru": {"question": "Что такое личная подписка?", "answer_html": "<p>Личная подписка отслеживает сервис или членство, которое вы оплачиваете сами, например Netflix, ChatGPT, абонемент в спортзал или программное обеспечение.</p>", "keywords": ["личная подписка", "членство", "сервис"]}}}, {"category_slug": "personal-subscriptions", "slug": "how-do-i-record-a-subscription-payment", "sort_order": 20, "translations": {"en": {"question": "How do I record a subscription payment?", "answer_html": "<p>Open the subscription and use the payment action to mark it paid so Smart Pocket can record the payment with the linked account and category.</p>", "keywords": ["subscription payment", "mark paid", "payment action"]}, "ar": {"question": "كيف أسجل دفعة اشتراك؟", "answer_html": "<p>افتح الاشتراك واستخدم إجراء الدفع أو التأشير كمدفوع حتى يتم تسجيل الدفعة بالحساب والفئة المرتبطين.</p>", "keywords": ["دفعة اشتراك", "تحديد كمدفوع", "إجراء الدفع"]}, "fr": {"question": "Comment enregistrer un paiement d''abonnement ?", "answer_html": "<p>Ouvrez l''abonnement et utilisez l''action de paiement pour le marquer comme payé afin que Smart Pocket enregistre la dépense avec le compte et la catégorie liés.</p>", "keywords": ["paiement abonnement", "marquer payé", "action paiement"]}, "ru": {"question": "Как записать оплату подписки?", "answer_html": "<p>Откройте подписку и используйте действие оплаты, чтобы отметить ее как оплаченную, и Smart Pocket сохранит платеж с привязанными счетом и категорией.</p>", "keywords": ["оплата подписки", "отметить как оплачено", "действие оплаты"]}}}, {"category_slug": "budgets", "slug": "how-do-i-create-a-budget", "sort_order": 10, "translations": {"en": {"question": "How do I create a budget?", "answer_html": "<p>Open Budgets, create a new budget, choose the category and amount, then review the period and any alert threshold settings.</p>", "keywords": ["create budget", "amount", "threshold"]}, "ar": {"question": "كيف أنشئ ميزانية؟", "answer_html": "<p>افتح Budgets، وأنشئ ميزانية جديدة، واختر الفئة والمبلغ، ثم راجع الفترة وإعدادات حد التنبيه.</p>", "keywords": ["إنشاء ميزانية", "المبلغ", "حد التنبيه"]}, "fr": {"question": "Comment créer un budget ?", "answer_html": "<p>Ouvrez Budgets, créez un nouveau budget, choisissez la catégorie et le montant, puis vérifiez la période et le seuil d''alerte.</p>", "keywords": ["créer budget", "montant", "seuil"]}, "ru": {"question": "Как создать бюджет?", "answer_html": "<p>Откройте Budgets, создайте новый бюджет, выберите категорию и сумму, затем проверьте период и порог уведомления.</p>", "keywords": ["создать бюджет", "сумма", "порог"]}}}, {"category_slug": "budgets", "slug": "what-happens-when-i-exceed-a-budget", "sort_order": 20, "translations": {"en": {"question": "What happens when I exceed a budget?", "answer_html": "<p>The budget shows that you have gone over target so you can review the category, adjust spending, or update the budget.</p>", "keywords": ["exceed budget", "over budget", "budget alert"]}, "ar": {"question": "ماذا يحدث عندما أتجاوز الميزانية؟", "answer_html": "<p>ستُظهر الميزانية أنك تجاوزت الهدف حتى تتمكن من مراجعة الفئة أو تعديل الإنفاق أو تحديث الميزانية.</p>", "keywords": ["تجاوز الميزانية", "فوق الميزانية", "تنبيه الميزانية"]}, "fr": {"question": "Que se passe-t-il lorsque je dépasse un budget ?", "answer_html": "<p>Le budget indique que vous avez dépassé la cible afin que vous puissiez revoir la catégorie, ajuster vos dépenses ou modifier le budget.</p>", "keywords": ["dépassement budget", "au-dessus budget", "alerte budget"]}, "ru": {"question": "Что происходит, если я превышаю бюджет?", "answer_html": "<p>Бюджет покажет превышение лимита, чтобы вы могли пересмотреть категорию, скорректировать расходы или изменить бюджет.</p>", "keywords": ["превышение бюджета", "сверх бюджета", "уведомление бюджета"]}}}, {"category_slug": "recurring-transactions", "slug": "what-is-a-recurring-transaction", "sort_order": 10, "translations": {"en": {"question": "What is a Recurring Transaction?", "answer_html": "<p>A Recurring Transaction is a scheduled financial entry for something that repeats regularly, such as rent, salary, allowance, or a routine transfer.</p>", "keywords": ["recurring transaction", "scheduled", "rent salary"]}, "ar": {"question": "ما هي المعاملة المتكررة؟", "answer_html": "<p>المعاملة المتكررة هي إدخال مالي مجدول لشيء يتكرر بانتظام، مثل الإيجار أو الراتب أو المصروف أو التحويل الدوري.</p>", "keywords": ["معاملة متكررة", "مجدول", "إيجار راتب"]}, "fr": {"question": "Qu''est-ce qu''une transaction récurrente ?", "answer_html": "<p>Une transaction récurrente est une écriture financière planifiée pour quelque chose qui se répète régulièrement, comme le loyer, le salaire, une allocation ou un transfert régulier.</p>", "keywords": ["transaction récurrente", "planifiée", "loyer salaire"]}, "ru": {"question": "Что такое повторяющаяся транзакция?", "answer_html": "<p>Повторяющаяся транзакция — это запланированная финансовая запись для того, что повторяется регулярно, например аренда, зарплата, пособие или регулярный перевод.</p>", "keywords": ["повторяющаяся транзакция", "запланированная", "аренда зарплата"]}}}, {"category_slug": "recurring-transactions", "slug": "what-is-the-difference-between-a-personal-subscription-and-a-recurring-transaction", "sort_order": 20, "is_featured": true, "translations": {"en": {"question": "What is the difference between a Personal Subscription and a Recurring Transaction?", "answer_html": "<p>Use Personal Subscription for a service or membership contract with provider, billing cycle, renewal date, and payment status. Use Recurring Transaction for a repeated financial activity such as rent, salary, allowance, or regular transfers.</p>", "keywords": ["personal subscription vs recurring", "membership", "repeating activity"]}, "ar": {"question": "ما الفرق بين الاشتراك الشخصي والمعاملة المتكررة؟", "answer_html": "<p>استخدم الاشتراك الشخصي لعقد خدمة أو عضوية يتضمن المزوّد ودورة الفوترة وتاريخ التجديد وحالة الدفع. واستخدم المعاملة المتكررة للنشاط المالي المتكرر مثل الإيجار أو الراتب أو التحويلات المنتظمة.</p>", "keywords": ["الاشتراك الشخصي مقابل المتكرر", "عضوية", "نشاط متكرر"]}, "fr": {"question": "Quelle est la différence entre un abonnement personnel et une transaction récurrente ?", "answer_html": "<p>Utilisez un abonnement personnel pour un service ou une adhésion avec fournisseur, cycle de facturation, date de renouvellement et statut de paiement. Utilisez une transaction récurrente pour une activité financière répétée comme le loyer, le salaire ou les transferts réguliers.</p>", "keywords": ["abonnement personnel vs récurrent", "adhésion", "activité répétée"]}, "ru": {"question": "Чем личная подписка отличается от повторяющейся транзакции?", "answer_html": "<p>Личная подписка подходит для сервисного договора или членства с поставщиком, циклом оплаты, датой продления и статусом платежа. Повторяющаяся транзакция используется для любой регулярной финансовой активности, например аренды, зарплаты или регулярных переводов.</p>", "keywords": ["личная подписка и повтор", "членство", "регулярная активность"]}}}, {"category_slug": "reimbursements", "slug": "what-is-a-reimbursement", "sort_order": 10, "translations": {"en": {"question": "What is a reimbursement?", "answer_html": "<p>A reimbursement records money that someone should pay back to you after you covered a cost on their behalf.</p>", "keywords": ["reimbursement", "owe me", "pay back"]}, "ar": {"question": "ما هو المبلغ المسترد؟", "answer_html": "<p>يسجل المبلغ المسترد مالاً يجب أن يعيده لك شخص آخر بعد أن دفعت أنت التكلفة نيابةً عنه.</p>", "keywords": ["مبلغ مسترد", "مدين لي", "إرجاع المال"]}, "fr": {"question": "Qu''est-ce qu''un remboursement ?", "answer_html": "<p>Un remboursement enregistre l''argent qu''une autre personne doit vous rendre après que vous avez payé une dépense pour elle.</p>", "keywords": ["remboursement", "me doit", "me rembourser"]}, "ru": {"question": "Что такое возмещение?", "answer_html": "<p>Возмещение фиксирует деньги, которые другой человек должен вернуть вам после того, как вы оплатили расход за него.</p>", "keywords": ["возмещение", "должны мне", "вернуть деньги"]}}}, {"category_slug": "reimbursements", "slug": "how-do-i-record-a-reimbursement-payment", "sort_order": 20, "translations": {"en": {"question": "How do I record a reimbursement payment?", "answer_html": "<p>Open the reimbursement and record the payment you received so the remaining amount and status update correctly.</p>", "keywords": ["reimbursement payment", "received payment", "status update"]}, "ar": {"question": "كيف أسجل دفعة مبلغ مسترد؟", "answer_html": "<p>افتح سجل المبلغ المسترد وسجّل الدفعة التي استلمتها حتى يتم تحديث المبلغ المتبقي والحالة بشكل صحيح.</p>", "keywords": ["دفعة مبلغ مسترد", "دفعة مستلمة", "تحديث الحالة"]}, "fr": {"question": "Comment enregistrer un paiement de remboursement ?", "answer_html": "<p>Ouvrez le remboursement et enregistrez le paiement reçu afin que le montant restant et le statut soient mis à jour correctement.</p>", "keywords": ["paiement remboursement", "paiement reçu", "mise à jour statut"]}, "ru": {"question": "Как записать платеж по возмещению?", "answer_html": "<p>Откройте запись о возмещении и зафиксируйте полученный платеж, чтобы оставшаяся сумма и статус обновились корректно.</p>", "keywords": ["платеж по возмещению", "полученный платеж", "обновление статуса"]}}}, {"category_slug": "settlements", "slug": "what-is-a-settlement", "sort_order": 10, "translations": {"en": {"question": "What is a settlement?", "answer_html": "<p>A settlement records money paid or received to clear a balance between you and another person.</p>", "keywords": ["settlement", "clear balance", "person balance"]}, "ar": {"question": "ما هي التسوية؟", "answer_html": "<p>تسجل التسوية مالاً تم دفعه أو استلامه لتصفية رصيد بينك وبين شخص آخر.</p>", "keywords": ["تسوية", "تصفية رصيد", "رصيد شخص"]}, "fr": {"question": "Qu''est-ce qu''un règlement ?", "answer_html": "<p>Un règlement enregistre l''argent payé ou reçu pour solder un équilibre entre vous et une autre personne.</p>", "keywords": ["règlement", "solder balance", "solde personne"]}, "ru": {"question": "Что такое расчет?", "answer_html": "<p>Расчет фиксирует деньги, уплаченные или полученные для закрытия баланса между вами и другим человеком.</p>", "keywords": ["расчет", "закрыть баланс", "баланс с человеком"]}}}, {"category_slug": "settlements", "slug": "what-is-the-difference-between-reimbursement-and-settlement", "sort_order": 20, "translations": {"en": {"question": "What is the difference between reimbursement and settlement?", "answer_html": "<p>A reimbursement tracks money that someone owes you back after you covered a cost. A settlement records the act of paying or receiving money to clear a balance.</p>", "keywords": ["reimbursement vs settlement", "owe me", "clear balance"]}, "ar": {"question": "ما الفرق بين المبلغ المسترد والتسوية؟", "answer_html": "<p>يتتبع المبلغ المسترد المال الذي يجب أن يعيده لك شخص آخر بعد أن دفعت عنه. أما التسوية فتسجل عملية دفع أو استلام المال لتصفية رصيد قائم.</p>", "keywords": ["المبلغ المسترد مقابل التسوية", "مدين لي", "تصفية الرصيد"]}, "fr": {"question": "Quelle est la différence entre remboursement et règlement ?", "answer_html": "<p>Le remboursement suit l''argent que quelqu''un doit vous rendre après que vous avez payé pour lui. Le règlement enregistre l''action de payer ou recevoir de l''argent pour solder un équilibre.</p>", "keywords": ["remboursement vs règlement", "me doit", "solder balance"]}, "ru": {"question": "Чем возмещение отличается от расчета?", "answer_html": "<p>Возмещение отслеживает деньги, которые вам должен вернуть другой человек после того, как вы заплатили за него. Расчет фиксирует сам факт оплаты или получения денег для закрытия баланса.</p>", "keywords": ["возмещение и расчет", "должны мне", "закрыть баланс"]}}}, {"category_slug": "people-spaces", "slug": "what-are-people", "sort_order": 10, "translations": {"en": {"question": "What are People?", "answer_html": "<p>People are contact-style records you can use when tracking balances, reimbursements, settlements, loans, or transactions that involve another person.</p>", "keywords": ["people", "person record", "balances"]}, "ar": {"question": "ما هم الأشخاص؟", "answer_html": "<p>الأشخاص هم سجلات شبيهة بجهات الاتصال يمكنك استخدامها عند تتبع الأرصدة أو المبالغ المستردة أو التسويات أو القروض أو المعاملات المرتبطة بشخص آخر.</p>", "keywords": ["الأشخاص", "سجل شخص", "أرصدة"]}, "fr": {"question": "Que sont les Personnes ?", "answer_html": "<p>Les personnes sont des fiches de contact que vous pouvez utiliser pour suivre les soldes, remboursements, règlements, prêts ou transactions impliquant une autre personne.</p>", "keywords": ["personnes", "fiche personne", "soldes"]}, "ru": {"question": "Что такое People?", "answer_html": "<p>People — это записи наподобие контактов, которые используются при отслеживании балансов, возмещений, расчетов, займов и транзакций с участием другого человека.</p>", "keywords": ["people", "запись человека", "балансы"]}}}, {"category_slug": "people-spaces", "slug": "what-are-spaces", "sort_order": 20, "translations": {"en": {"question": "What are Spaces?", "answer_html": "<p>Spaces help you separate activity into contexts such as family, work, or a shared household, with room for members and role-based participation.</p>", "keywords": ["spaces", "shared household", "members"]}, "ar": {"question": "ما هي المساحات؟", "answer_html": "<p>تساعدك المساحات على فصل الأنشطة حسب السياق مثل العائلة أو العمل أو المنزل المشترك، مع إمكانية وجود أعضاء وأدوار مختلفة.</p>", "keywords": ["المساحات", "منزل مشترك", "أعضاء"]}, "fr": {"question": "Que sont les Espaces ?", "answer_html": "<p>Les espaces permettent de séparer l''activité par contexte, comme la famille, le travail ou un foyer partagé, avec des membres et des rôles.</p>", "keywords": ["espaces", "foyer partagé", "membres"]}, "ru": {"question": "Что такое Spaces?", "answer_html": "<p>Spaces помогают разделять активность по контекстам, например семья, работа или общее хозяйство, с участниками и ролями.</p>", "keywords": ["spaces", "общее хозяйство", "участники"]}}}, {"category_slug": "plans-subscriptions", "slug": "what-smart-pocket-plans-are-available", "sort_order": 10, "translations": {"en": {"question": "What Smart Pocket plans are available?", "answer_html": "<p>The available Smart Pocket plans depend on the current platform configuration. Open the subscription area to view the live plans and current billing options.</p>", "keywords": ["plans", "subscription plans", "billing"]}, "ar": {"question": "ما خطط Smart Pocket المتاحة؟", "answer_html": "<p>تعتمد خطط Smart Pocket المتاحة على إعدادات المنصة الحالية. افتح قسم الاشتراك لعرض الخطط الفعلية وخيارات الفوترة الحالية.</p>", "keywords": ["الخطط", "خطط الاشتراك", "الفوترة"]}, "fr": {"question": "Quels forfaits Smart Pocket sont disponibles ?", "answer_html": "<p>Les forfaits Smart Pocket disponibles dépendent de la configuration actuelle de la plateforme. Ouvrez la zone d''abonnement pour voir les offres actives et leurs options de facturation.</p>", "keywords": ["forfaits", "plans abonnement", "facturation"]}, "ru": {"question": "Какие тарифы Smart Pocket доступны?", "answer_html": "<p>Доступные тарифы Smart Pocket зависят от текущей конфигурации платформы. Откройте раздел подписки, чтобы увидеть актуальные планы и варианты оплаты.</p>", "keywords": ["тарифы", "планы подписки", "оплата"]}}}, {"category_slug": "plans-subscriptions", "slug": "where-can-i-view-my-current-plan", "sort_order": 20, "translations": {"en": {"question": "Where can I view my current plan?", "answer_html": "<p>Open your subscription settings to view the plan currently attached to your account and the billing details available there.</p>", "keywords": ["current plan", "subscription settings", "billing details"]}, "ar": {"question": "أين يمكنني عرض خطتي الحالية؟", "answer_html": "<p>افتح إعدادات الاشتراك لعرض الخطة المرتبطة حالياً بحسابك وتفاصيل الفوترة المتاحة هناك.</p>", "keywords": ["الخطة الحالية", "إعدادات الاشتراك", "تفاصيل الفوترة"]}, "fr": {"question": "Où puis-je voir mon forfait actuel ?", "answer_html": "<p>Ouvrez les paramètres d''abonnement pour consulter le forfait actuellement lié à votre compte ainsi que les détails de facturation disponibles.</p>", "keywords": ["forfait actuel", "paramètres abonnement", "détails facturation"]}, "ru": {"question": "Где посмотреть мой текущий тариф?", "answer_html": "<p>Откройте настройки подписки, чтобы увидеть тариф, подключенный к вашему аккаунту, и доступные там платежные детали.</p>", "keywords": ["текущий тариф", "настройки подписки", "платежные детали"]}}}, {"category_slug": "support-troubleshooting", "slug": "how-do-i-create-a-support-ticket", "sort_order": 10, "translations": {"en": {"question": "How do I create a support ticket?", "answer_html": "<p>Signed-in users can open /support/new to create a ticket. You can also review your existing ticket list from /support.</p>", "keywords": ["support ticket", "support new", "support list"]}, "ar": {"question": "كيف أنشئ تذكرة دعم؟", "answer_html": "<p>يمكن للمستخدمين المسجلين فتح /support/new لإنشاء تذكرة. كما يمكنك مراجعة قائمة التذاكر الحالية من /support.</p>", "keywords": ["تذكرة دعم", "دعم جديد", "قائمة الدعم"]}, "fr": {"question": "Comment créer un ticket de support ?", "answer_html": "<p>Les utilisateurs connectés peuvent ouvrir /support/new pour créer un ticket. Vous pouvez également consulter la liste de vos tickets depuis /support.</p>", "keywords": ["ticket support", "support new", "liste support"]}, "ru": {"question": "Как создать тикет поддержки?", "answer_html": "<p>Авторизованные пользователи могут открыть /support/new для создания тикета. Список текущих тикетов доступен на /support.</p>", "keywords": ["тикет поддержки", "support new", "список support"]}}}, {"category_slug": "support-troubleshooting", "slug": "can-i-attach-screenshots-or-pdfs", "sort_order": 20, "translations": {"en": {"question": "Can I attach screenshots or PDFs?", "answer_html": "<p>Yes. Support tickets can include private attachments such as screenshots or PDF files when they help explain the issue.</p>", "keywords": ["attachments", "screenshots", "pdf"]}, "ar": {"question": "هل يمكنني إرفاق لقطات شاشة أو ملفات PDF؟", "answer_html": "<p>نعم. يمكن أن تتضمن تذاكر الدعم مرفقات خاصة مثل لقطات الشاشة أو ملفات PDF عندما تساعد في شرح المشكلة.</p>", "keywords": ["مرفقات", "لقطات شاشة", "pdf"]}, "fr": {"question": "Puis-je joindre des captures d''écran ou des PDF ?", "answer_html": "<p>Oui. Les tickets de support peuvent inclure des pièces jointes privées comme des captures d''écran ou des fichiers PDF lorsqu''elles aident à expliquer le problème.</p>", "keywords": ["pièces jointes", "captures écran", "pdf"]}, "ru": {"question": "Можно ли прикреплять скриншоты или PDF?", "answer_html": "<p>Да. К тикетам поддержки можно прикреплять приватные вложения, например скриншоты или PDF, если они помогают объяснить проблему.</p>", "keywords": ["вложения", "скриншоты", "pdf"]}}}]'::jsonb AS data
)
INSERT INTO public.faq_items (category_id, slug, sort_order, is_active, is_featured)
SELECT
  c.id,
  entry ->> 'slug',
  COALESCE((entry ->> 'sort_order')::INTEGER, 0),
  true,
  COALESCE((entry ->> 'is_featured')::BOOLEAN, false)
FROM item_seed
CROSS JOIN LATERAL jsonb_array_elements(item_seed.data) AS entry
JOIN public.faq_categories c ON c.slug = entry ->> 'category_slug'
ON CONFLICT (slug) DO UPDATE
SET category_id = EXCLUDED.category_id,
    sort_order = EXCLUDED.sort_order,
    is_active = EXCLUDED.is_active,
    is_featured = EXCLUDED.is_featured;

WITH item_seed AS (
  SELECT '[{"category_slug": "getting-started", "slug": "what-is-smart-pocket", "sort_order": 10, "is_featured": true, "translations": {"en": {"question": "What is Smart Pocket?", "answer_html": "<p>Smart Pocket is a personal finance app for tracking accounts, transactions, budgets, recurring activity, reimbursements, and reports in one place.</p>", "keywords": ["smart pocket", "finance app", "money tracking"]}, "ar": {"question": "ما هو Smart Pocket؟", "answer_html": "<p>Smart Pocket هو تطبيق لإدارة المال الشخصي يساعدك على تتبع الحسابات والمعاملات والميزانيات والعمليات المتكررة والمبالغ المستردة والتقارير في مكان واحد.</p>", "keywords": ["سمارت بوكيت", "تطبيق مالي", "تتبع الأموال"]}, "fr": {"question": "Qu''est-ce que Smart Pocket ?", "answer_html": "<p>Smart Pocket est une application de finance personnelle qui centralise comptes, transactions, budgets, opérations récurrentes, remboursements et rapports.</p>", "keywords": ["smart pocket", "application finance", "suivi argent"]}, "ru": {"question": "Что такое Smart Pocket?", "answer_html": "<p>Smart Pocket — это приложение для личных финансов, где можно вести счета, транзакции, бюджеты, регулярные операции, возмещения и отчеты в одном месте.</p>", "keywords": ["smart pocket", "финансовое приложение", "учет денег"]}}}, {"category_slug": "getting-started", "slug": "what-should-i-configure-first", "sort_order": 20, "translations": {"en": {"question": "What should I configure first?", "answer_html": "<p>Start with your profile, default currency, and the default Cash and Bank accounts, then record your first transaction so balances and reports begin with useful data.</p>", "keywords": ["profile", "default currency", "cash bank"]}, "ar": {"question": "ما الذي يجب أن أعدّه أولاً؟", "answer_html": "<p>ابدأ بملفك الشخصي والعملة الافتراضية وحسابي Cash وBank الافتراضيين، ثم سجّل أول معاملة حتى تبدأ الأرصدة والتقارير ببيانات مفيدة.</p>", "keywords": ["الملف الشخصي", "العملة الافتراضية", "النقد والبنك"]}, "fr": {"question": "Que dois-je configurer en premier ?", "answer_html": "<p>Commencez par votre profil, votre devise par défaut et les comptes Cash et Bank par défaut, puis enregistrez votre première transaction pour alimenter les soldes et rapports.</p>", "keywords": ["profil", "devise par défaut", "cash bank"]}, "ru": {"question": "Что настроить в первую очередь?", "answer_html": "<p>Сначала заполните профиль, валюту по умолчанию и стандартные счета Cash и Bank, а затем внесите первую транзакцию, чтобы балансы и отчеты стали полезными.</p>", "keywords": ["профиль", "валюта по умолчанию", "cash bank"]}}}, {"category_slug": "ai-smart-entry", "slug": "what-is-smart-entry", "sort_order": 10, "is_featured": true, "translations": {"en": {"question": "What is Smart Entry?", "answer_html": "<p>Smart Entry lets you describe one or more financial actions in natural language and turns them into draft records for review before saving.</p>", "keywords": ["smart entry", "ai", "drafts"]}, "ar": {"question": "ما هو الإدخال الذكي؟", "answer_html": "<p>يتيح لك الإدخال الذكي وصف إجراء مالي واحد أو عدة إجراءات بلغة طبيعية ثم يحولها إلى مسودات جاهزة للمراجعة قبل الحفظ.</p>", "keywords": ["الإدخال الذكي", "ذكاء اصطناعي", "مسودات"]}, "fr": {"question": "Qu''est-ce que Smart Entry ?", "answer_html": "<p>Smart Entry vous permet de décrire une ou plusieurs actions financières en langage naturel et les transforme en brouillons à vérifier avant l''enregistrement.</p>", "keywords": ["smart entry", "ia", "brouillons"]}, "ru": {"question": "Что такое Smart Entry?", "answer_html": "<p>Smart Entry позволяет описать одно или несколько финансовых действий обычным языком и превращает их в черновики для проверки перед сохранением.</p>", "keywords": ["smart entry", "ии", "черновики"]}}}, {"category_slug": "ai-smart-entry", "slug": "why-must-i-review-ai-results-before-saving", "sort_order": 20, "translations": {"en": {"question": "Why must I review AI results before saving?", "answer_html": "<p>AI suggestions are drafts, not final records. Review them to confirm amounts, dates, categories, accounts, and direction before anything is saved.</p>", "keywords": ["review ai", "confirm", "before saving"]}, "ar": {"question": "لماذا يجب أن أراجع نتائج الذكاء الاصطناعي قبل الحفظ؟", "answer_html": "<p>اقتراحات الذكاء الاصطناعي هي مسودات وليست سجلات نهائية. راجعها للتأكد من المبالغ والتواريخ والفئات والحسابات والاتجاه قبل الحفظ.</p>", "keywords": ["مراجعة الذكاء الاصطناعي", "التأكيد", "قبل الحفظ"]}, "fr": {"question": "Pourquoi faut-il vérifier les résultats de l''IA avant d''enregistrer ?", "answer_html": "<p>Les suggestions de l''IA sont des brouillons, pas des écritures finales. Vérifiez montants, dates, catégories, comptes et sens avant l''enregistrement.</p>", "keywords": ["vérifier ia", "confirmer", "avant enregistrement"]}, "ru": {"question": "Почему нужно проверять результаты ИИ перед сохранением?", "answer_html": "<p>Подсказки ИИ — это черновики, а не окончательные записи. Проверьте суммы, даты, категории, счета и направление операции до сохранения.</p>", "keywords": ["проверка ии", "подтвердить", "до сохранения"]}}}, {"category_slug": "transactions", "slug": "how-do-i-add-an-expense", "sort_order": 10, "translations": {"en": {"question": "How do I add an expense?", "answer_html": "<p>Open Add Transaction, choose Expense, select the account to pay from, then enter the amount, category, date, and notes.</p>", "keywords": ["expense", "add transaction", "pay from"]}, "ar": {"question": "كيف أضيف مصروفاً؟", "answer_html": "<p>افتح إضافة معاملة، واختر Expense، وحدد الحساب الذي ستدفع منه، ثم أدخل المبلغ والفئة والتاريخ والملاحظات.</p>", "keywords": ["مصروف", "إضافة معاملة", "الدفع من"]}, "fr": {"question": "Comment ajouter une dépense ?", "answer_html": "<p>Ouvrez Ajouter une transaction, choisissez Expense, sélectionnez le compte à débiter, puis saisissez le montant, la catégorie, la date et les notes.</p>", "keywords": ["dépense", "ajouter transaction", "payer depuis"]}, "ru": {"question": "Как добавить расход?", "answer_html": "<p>Откройте добавление транзакции, выберите Expense, укажите счет списания, затем введите сумму, категорию, дату и заметки.</p>", "keywords": ["расход", "добавить транзакцию", "оплатить со счета"]}}}, {"category_slug": "transactions", "slug": "how-are-categories-used", "sort_order": 20, "translations": {"en": {"question": "How are categories used?", "answer_html": "<p>Categories organize spending and income for reports, filters, and budgets. Use Groceries & Household for supermarket and home essentials, and Dining Out for restaurants, cafes, and takeout.</p>", "keywords": ["categories", "groceries household", "dining out"]}, "ar": {"question": "كيف تُستخدم الفئات؟", "answer_html": "<p>تنظم الفئات المصروفات والدخل داخل التقارير والفلاتر والميزانيات. استخدم Groceries & Household لمشتريات السوبرماركت ولوازم المنزل، وDining Out للمطاعم والمقاهي والطلبات الخارجية.</p>", "keywords": ["الفئات", "مشتريات المنزل", "تناول الطعام خارج المنزل"]}, "fr": {"question": "Comment les catégories sont-elles utilisées ?", "answer_html": "<p>Les catégories organisent dépenses et revenus dans les rapports, filtres et budgets. Utilisez Groceries & Household pour le supermarché et la maison, et Dining Out pour restaurants, cafés et plats à emporter.</p>", "keywords": ["catégories", "courses maison", "repas à l''extérieur"]}, "ru": {"question": "Как используются категории?", "answer_html": "<p>Категории помогают упорядочивать расходы и доходы в отчетах, фильтрах и бюджетах. Используйте Groceries & Household для супермаркета и товаров для дома, а Dining Out — для ресторанов, кафе и доставки.</p>", "keywords": ["категории", "продукты и дом", "еда вне дома"]}}}, {"category_slug": "accounts", "slug": "what-is-a-financial-account", "sort_order": 10, "translations": {"en": {"question": "What is a financial account?", "answer_html": "<p>A financial account is any place where money is stored, spent from, or received into, such as cash, a bank account, or another tracked account.</p>", "keywords": ["financial account", "cash", "bank"]}, "ar": {"question": "ما هو الحساب المالي؟", "answer_html": "<p>الحساب المالي هو أي مكان تُحفظ فيه الأموال أو تُنفق منه أو تُستلم فيه، مثل النقد أو الحساب البنكي أو أي حساب آخر تتم متابعته.</p>", "keywords": ["حساب مالي", "نقد", "بنك"]}, "fr": {"question": "Qu''est-ce qu''un compte financier ?", "answer_html": "<p>Un compte financier est tout endroit où l''argent est conservé, dépensé ou reçu, comme du cash, un compte bancaire ou tout autre compte suivi.</p>", "keywords": ["compte financier", "cash", "banque"]}, "ru": {"question": "Что такое финансовый счет?", "answer_html": "<p>Финансовый счет — это любое место, где хранятся деньги, откуда они тратятся или куда поступают: наличные, банковский счет или другой отслеживаемый счет.</p>", "keywords": ["финансовый счет", "наличные", "банк"]}}}, {"category_slug": "accounts", "slug": "how-do-transfers-between-accounts-work", "sort_order": 20, "translations": {"en": {"question": "How do transfers between accounts work?", "answer_html": "<p>A transfer moves money from one financial account to another without treating it as new income or a new expense.</p>", "keywords": ["transfer", "between accounts", "move money"]}, "ar": {"question": "كيف تعمل التحويلات بين الحسابات؟", "answer_html": "<p>يقوم التحويل بنقل المال من حساب مالي إلى آخر دون اعتباره دخلاً جديداً أو مصروفاً جديداً.</p>", "keywords": ["تحويل", "بين الحسابات", "نقل المال"]}, "fr": {"question": "Comment fonctionnent les transferts entre comptes ?", "answer_html": "<p>Un transfert déplace l''argent d''un compte financier vers un autre sans le considérer comme un nouveau revenu ou une nouvelle dépense.</p>", "keywords": ["transfert", "entre comptes", "déplacer argent"]}, "ru": {"question": "Как работают переводы между счетами?", "answer_html": "<p>Перевод перемещает деньги с одного финансового счета на другой и не считается новым доходом или расходом.</p>", "keywords": ["перевод", "между счетами", "переместить деньги"]}}}, {"category_slug": "personal-subscriptions", "slug": "what-is-a-personal-subscription", "sort_order": 10, "is_featured": true, "translations": {"en": {"question": "What is a Personal Subscription?", "answer_html": "<p>A Personal Subscription tracks a service or membership you personally pay for, such as Netflix, ChatGPT, a gym membership, or software.</p>", "keywords": ["personal subscription", "membership", "service"]}, "ar": {"question": "ما هو الاشتراك الشخصي؟", "answer_html": "<p>الاشتراك الشخصي يتتبع خدمة أو عضوية تدفعها أنت شخصياً، مثل Netflix أو ChatGPT أو عضوية النادي أو البرامج.</p>", "keywords": ["اشتراك شخصي", "عضوية", "خدمة"]}, "fr": {"question": "Qu''est-ce qu''un abonnement personnel ?", "answer_html": "<p>Un abonnement personnel suit un service ou une adhésion que vous payez personnellement, comme Netflix, ChatGPT, un abonnement de sport ou un logiciel.</p>", "keywords": ["abonnement personnel", "adhésion", "service"]}, "ru": {"question": "Что такое личная подписка?", "answer_html": "<p>Личная подписка отслеживает сервис или членство, которое вы оплачиваете сами, например Netflix, ChatGPT, абонемент в спортзал или программное обеспечение.</p>", "keywords": ["личная подписка", "членство", "сервис"]}}}, {"category_slug": "personal-subscriptions", "slug": "how-do-i-record-a-subscription-payment", "sort_order": 20, "translations": {"en": {"question": "How do I record a subscription payment?", "answer_html": "<p>Open the subscription and use the payment action to mark it paid so Smart Pocket can record the payment with the linked account and category.</p>", "keywords": ["subscription payment", "mark paid", "payment action"]}, "ar": {"question": "كيف أسجل دفعة اشتراك؟", "answer_html": "<p>افتح الاشتراك واستخدم إجراء الدفع أو التأشير كمدفوع حتى يتم تسجيل الدفعة بالحساب والفئة المرتبطين.</p>", "keywords": ["دفعة اشتراك", "تحديد كمدفوع", "إجراء الدفع"]}, "fr": {"question": "Comment enregistrer un paiement d''abonnement ?", "answer_html": "<p>Ouvrez l''abonnement et utilisez l''action de paiement pour le marquer comme payé afin que Smart Pocket enregistre la dépense avec le compte et la catégorie liés.</p>", "keywords": ["paiement abonnement", "marquer payé", "action paiement"]}, "ru": {"question": "Как записать оплату подписки?", "answer_html": "<p>Откройте подписку и используйте действие оплаты, чтобы отметить ее как оплаченную, и Smart Pocket сохранит платеж с привязанными счетом и категорией.</p>", "keywords": ["оплата подписки", "отметить как оплачено", "действие оплаты"]}}}, {"category_slug": "budgets", "slug": "how-do-i-create-a-budget", "sort_order": 10, "translations": {"en": {"question": "How do I create a budget?", "answer_html": "<p>Open Budgets, create a new budget, choose the category and amount, then review the period and any alert threshold settings.</p>", "keywords": ["create budget", "amount", "threshold"]}, "ar": {"question": "كيف أنشئ ميزانية؟", "answer_html": "<p>افتح Budgets، وأنشئ ميزانية جديدة، واختر الفئة والمبلغ، ثم راجع الفترة وإعدادات حد التنبيه.</p>", "keywords": ["إنشاء ميزانية", "المبلغ", "حد التنبيه"]}, "fr": {"question": "Comment créer un budget ?", "answer_html": "<p>Ouvrez Budgets, créez un nouveau budget, choisissez la catégorie et le montant, puis vérifiez la période et le seuil d''alerte.</p>", "keywords": ["créer budget", "montant", "seuil"]}, "ru": {"question": "Как создать бюджет?", "answer_html": "<p>Откройте Budgets, создайте новый бюджет, выберите категорию и сумму, затем проверьте период и порог уведомления.</p>", "keywords": ["создать бюджет", "сумма", "порог"]}}}, {"category_slug": "budgets", "slug": "what-happens-when-i-exceed-a-budget", "sort_order": 20, "translations": {"en": {"question": "What happens when I exceed a budget?", "answer_html": "<p>The budget shows that you have gone over target so you can review the category, adjust spending, or update the budget.</p>", "keywords": ["exceed budget", "over budget", "budget alert"]}, "ar": {"question": "ماذا يحدث عندما أتجاوز الميزانية؟", "answer_html": "<p>ستُظهر الميزانية أنك تجاوزت الهدف حتى تتمكن من مراجعة الفئة أو تعديل الإنفاق أو تحديث الميزانية.</p>", "keywords": ["تجاوز الميزانية", "فوق الميزانية", "تنبيه الميزانية"]}, "fr": {"question": "Que se passe-t-il lorsque je dépasse un budget ?", "answer_html": "<p>Le budget indique que vous avez dépassé la cible afin que vous puissiez revoir la catégorie, ajuster vos dépenses ou modifier le budget.</p>", "keywords": ["dépassement budget", "au-dessus budget", "alerte budget"]}, "ru": {"question": "Что происходит, если я превышаю бюджет?", "answer_html": "<p>Бюджет покажет превышение лимита, чтобы вы могли пересмотреть категорию, скорректировать расходы или изменить бюджет.</p>", "keywords": ["превышение бюджета", "сверх бюджета", "уведомление бюджета"]}}}, {"category_slug": "recurring-transactions", "slug": "what-is-a-recurring-transaction", "sort_order": 10, "translations": {"en": {"question": "What is a Recurring Transaction?", "answer_html": "<p>A Recurring Transaction is a scheduled financial entry for something that repeats regularly, such as rent, salary, allowance, or a routine transfer.</p>", "keywords": ["recurring transaction", "scheduled", "rent salary"]}, "ar": {"question": "ما هي المعاملة المتكررة؟", "answer_html": "<p>المعاملة المتكررة هي إدخال مالي مجدول لشيء يتكرر بانتظام، مثل الإيجار أو الراتب أو المصروف أو التحويل الدوري.</p>", "keywords": ["معاملة متكررة", "مجدول", "إيجار راتب"]}, "fr": {"question": "Qu''est-ce qu''une transaction récurrente ?", "answer_html": "<p>Une transaction récurrente est une écriture financière planifiée pour quelque chose qui se répète régulièrement, comme le loyer, le salaire, une allocation ou un transfert régulier.</p>", "keywords": ["transaction récurrente", "planifiée", "loyer salaire"]}, "ru": {"question": "Что такое повторяющаяся транзакция?", "answer_html": "<p>Повторяющаяся транзакция — это запланированная финансовая запись для того, что повторяется регулярно, например аренда, зарплата, пособие или регулярный перевод.</p>", "keywords": ["повторяющаяся транзакция", "запланированная", "аренда зарплата"]}}}, {"category_slug": "recurring-transactions", "slug": "what-is-the-difference-between-a-personal-subscription-and-a-recurring-transaction", "sort_order": 20, "is_featured": true, "translations": {"en": {"question": "What is the difference between a Personal Subscription and a Recurring Transaction?", "answer_html": "<p>Use Personal Subscription for a service or membership contract with provider, billing cycle, renewal date, and payment status. Use Recurring Transaction for a repeated financial activity such as rent, salary, allowance, or regular transfers.</p>", "keywords": ["personal subscription vs recurring", "membership", "repeating activity"]}, "ar": {"question": "ما الفرق بين الاشتراك الشخصي والمعاملة المتكررة؟", "answer_html": "<p>استخدم الاشتراك الشخصي لعقد خدمة أو عضوية يتضمن المزوّد ودورة الفوترة وتاريخ التجديد وحالة الدفع. واستخدم المعاملة المتكررة للنشاط المالي المتكرر مثل الإيجار أو الراتب أو التحويلات المنتظمة.</p>", "keywords": ["الاشتراك الشخصي مقابل المتكرر", "عضوية", "نشاط متكرر"]}, "fr": {"question": "Quelle est la différence entre un abonnement personnel et une transaction récurrente ?", "answer_html": "<p>Utilisez un abonnement personnel pour un service ou une adhésion avec fournisseur, cycle de facturation, date de renouvellement et statut de paiement. Utilisez une transaction récurrente pour une activité financière répétée comme le loyer, le salaire ou les transferts réguliers.</p>", "keywords": ["abonnement personnel vs récurrent", "adhésion", "activité répétée"]}, "ru": {"question": "Чем личная подписка отличается от повторяющейся транзакции?", "answer_html": "<p>Личная подписка подходит для сервисного договора или членства с поставщиком, циклом оплаты, датой продления и статусом платежа. Повторяющаяся транзакция используется для любой регулярной финансовой активности, например аренды, зарплаты или регулярных переводов.</p>", "keywords": ["личная подписка и повтор", "членство", "регулярная активность"]}}}, {"category_slug": "reimbursements", "slug": "what-is-a-reimbursement", "sort_order": 10, "translations": {"en": {"question": "What is a reimbursement?", "answer_html": "<p>A reimbursement records money that someone should pay back to you after you covered a cost on their behalf.</p>", "keywords": ["reimbursement", "owe me", "pay back"]}, "ar": {"question": "ما هو المبلغ المسترد؟", "answer_html": "<p>يسجل المبلغ المسترد مالاً يجب أن يعيده لك شخص آخر بعد أن دفعت أنت التكلفة نيابةً عنه.</p>", "keywords": ["مبلغ مسترد", "مدين لي", "إرجاع المال"]}, "fr": {"question": "Qu''est-ce qu''un remboursement ?", "answer_html": "<p>Un remboursement enregistre l''argent qu''une autre personne doit vous rendre après que vous avez payé une dépense pour elle.</p>", "keywords": ["remboursement", "me doit", "me rembourser"]}, "ru": {"question": "Что такое возмещение?", "answer_html": "<p>Возмещение фиксирует деньги, которые другой человек должен вернуть вам после того, как вы оплатили расход за него.</p>", "keywords": ["возмещение", "должны мне", "вернуть деньги"]}}}, {"category_slug": "reimbursements", "slug": "how-do-i-record-a-reimbursement-payment", "sort_order": 20, "translations": {"en": {"question": "How do I record a reimbursement payment?", "answer_html": "<p>Open the reimbursement and record the payment you received so the remaining amount and status update correctly.</p>", "keywords": ["reimbursement payment", "received payment", "status update"]}, "ar": {"question": "كيف أسجل دفعة مبلغ مسترد؟", "answer_html": "<p>افتح سجل المبلغ المسترد وسجّل الدفعة التي استلمتها حتى يتم تحديث المبلغ المتبقي والحالة بشكل صحيح.</p>", "keywords": ["دفعة مبلغ مسترد", "دفعة مستلمة", "تحديث الحالة"]}, "fr": {"question": "Comment enregistrer un paiement de remboursement ?", "answer_html": "<p>Ouvrez le remboursement et enregistrez le paiement reçu afin que le montant restant et le statut soient mis à jour correctement.</p>", "keywords": ["paiement remboursement", "paiement reçu", "mise à jour statut"]}, "ru": {"question": "Как записать платеж по возмещению?", "answer_html": "<p>Откройте запись о возмещении и зафиксируйте полученный платеж, чтобы оставшаяся сумма и статус обновились корректно.</p>", "keywords": ["платеж по возмещению", "полученный платеж", "обновление статуса"]}}}, {"category_slug": "settlements", "slug": "what-is-a-settlement", "sort_order": 10, "translations": {"en": {"question": "What is a settlement?", "answer_html": "<p>A settlement records money paid or received to clear a balance between you and another person.</p>", "keywords": ["settlement", "clear balance", "person balance"]}, "ar": {"question": "ما هي التسوية؟", "answer_html": "<p>تسجل التسوية مالاً تم دفعه أو استلامه لتصفية رصيد بينك وبين شخص آخر.</p>", "keywords": ["تسوية", "تصفية رصيد", "رصيد شخص"]}, "fr": {"question": "Qu''est-ce qu''un règlement ?", "answer_html": "<p>Un règlement enregistre l''argent payé ou reçu pour solder un équilibre entre vous et une autre personne.</p>", "keywords": ["règlement", "solder balance", "solde personne"]}, "ru": {"question": "Что такое расчет?", "answer_html": "<p>Расчет фиксирует деньги, уплаченные или полученные для закрытия баланса между вами и другим человеком.</p>", "keywords": ["расчет", "закрыть баланс", "баланс с человеком"]}}}, {"category_slug": "settlements", "slug": "what-is-the-difference-between-reimbursement-and-settlement", "sort_order": 20, "translations": {"en": {"question": "What is the difference between reimbursement and settlement?", "answer_html": "<p>A reimbursement tracks money that someone owes you back after you covered a cost. A settlement records the act of paying or receiving money to clear a balance.</p>", "keywords": ["reimbursement vs settlement", "owe me", "clear balance"]}, "ar": {"question": "ما الفرق بين المبلغ المسترد والتسوية؟", "answer_html": "<p>يتتبع المبلغ المسترد المال الذي يجب أن يعيده لك شخص آخر بعد أن دفعت عنه. أما التسوية فتسجل عملية دفع أو استلام المال لتصفية رصيد قائم.</p>", "keywords": ["المبلغ المسترد مقابل التسوية", "مدين لي", "تصفية الرصيد"]}, "fr": {"question": "Quelle est la différence entre remboursement et règlement ?", "answer_html": "<p>Le remboursement suit l''argent que quelqu''un doit vous rendre après que vous avez payé pour lui. Le règlement enregistre l''action de payer ou recevoir de l''argent pour solder un équilibre.</p>", "keywords": ["remboursement vs règlement", "me doit", "solder balance"]}, "ru": {"question": "Чем возмещение отличается от расчета?", "answer_html": "<p>Возмещение отслеживает деньги, которые вам должен вернуть другой человек после того, как вы заплатили за него. Расчет фиксирует сам факт оплаты или получения денег для закрытия баланса.</p>", "keywords": ["возмещение и расчет", "должны мне", "закрыть баланс"]}}}, {"category_slug": "people-spaces", "slug": "what-are-people", "sort_order": 10, "translations": {"en": {"question": "What are People?", "answer_html": "<p>People are contact-style records you can use when tracking balances, reimbursements, settlements, loans, or transactions that involve another person.</p>", "keywords": ["people", "person record", "balances"]}, "ar": {"question": "ما هم الأشخاص؟", "answer_html": "<p>الأشخاص هم سجلات شبيهة بجهات الاتصال يمكنك استخدامها عند تتبع الأرصدة أو المبالغ المستردة أو التسويات أو القروض أو المعاملات المرتبطة بشخص آخر.</p>", "keywords": ["الأشخاص", "سجل شخص", "أرصدة"]}, "fr": {"question": "Que sont les Personnes ?", "answer_html": "<p>Les personnes sont des fiches de contact que vous pouvez utiliser pour suivre les soldes, remboursements, règlements, prêts ou transactions impliquant une autre personne.</p>", "keywords": ["personnes", "fiche personne", "soldes"]}, "ru": {"question": "Что такое People?", "answer_html": "<p>People — это записи наподобие контактов, которые используются при отслеживании балансов, возмещений, расчетов, займов и транзакций с участием другого человека.</p>", "keywords": ["people", "запись человека", "балансы"]}}}, {"category_slug": "people-spaces", "slug": "what-are-spaces", "sort_order": 20, "translations": {"en": {"question": "What are Spaces?", "answer_html": "<p>Spaces help you separate activity into contexts such as family, work, or a shared household, with room for members and role-based participation.</p>", "keywords": ["spaces", "shared household", "members"]}, "ar": {"question": "ما هي المساحات؟", "answer_html": "<p>تساعدك المساحات على فصل الأنشطة حسب السياق مثل العائلة أو العمل أو المنزل المشترك، مع إمكانية وجود أعضاء وأدوار مختلفة.</p>", "keywords": ["المساحات", "منزل مشترك", "أعضاء"]}, "fr": {"question": "Que sont les Espaces ?", "answer_html": "<p>Les espaces permettent de séparer l''activité par contexte, comme la famille, le travail ou un foyer partagé, avec des membres et des rôles.</p>", "keywords": ["espaces", "foyer partagé", "membres"]}, "ru": {"question": "Что такое Spaces?", "answer_html": "<p>Spaces помогают разделять активность по контекстам, например семья, работа или общее хозяйство, с участниками и ролями.</p>", "keywords": ["spaces", "общее хозяйство", "участники"]}}}, {"category_slug": "plans-subscriptions", "slug": "what-smart-pocket-plans-are-available", "sort_order": 10, "translations": {"en": {"question": "What Smart Pocket plans are available?", "answer_html": "<p>The available Smart Pocket plans depend on the current platform configuration. Open the subscription area to view the live plans and current billing options.</p>", "keywords": ["plans", "subscription plans", "billing"]}, "ar": {"question": "ما خطط Smart Pocket المتاحة؟", "answer_html": "<p>تعتمد خطط Smart Pocket المتاحة على إعدادات المنصة الحالية. افتح قسم الاشتراك لعرض الخطط الفعلية وخيارات الفوترة الحالية.</p>", "keywords": ["الخطط", "خطط الاشتراك", "الفوترة"]}, "fr": {"question": "Quels forfaits Smart Pocket sont disponibles ?", "answer_html": "<p>Les forfaits Smart Pocket disponibles dépendent de la configuration actuelle de la plateforme. Ouvrez la zone d''abonnement pour voir les offres actives et leurs options de facturation.</p>", "keywords": ["forfaits", "plans abonnement", "facturation"]}, "ru": {"question": "Какие тарифы Smart Pocket доступны?", "answer_html": "<p>Доступные тарифы Smart Pocket зависят от текущей конфигурации платформы. Откройте раздел подписки, чтобы увидеть актуальные планы и варианты оплаты.</p>", "keywords": ["тарифы", "планы подписки", "оплата"]}}}, {"category_slug": "plans-subscriptions", "slug": "where-can-i-view-my-current-plan", "sort_order": 20, "translations": {"en": {"question": "Where can I view my current plan?", "answer_html": "<p>Open your subscription settings to view the plan currently attached to your account and the billing details available there.</p>", "keywords": ["current plan", "subscription settings", "billing details"]}, "ar": {"question": "أين يمكنني عرض خطتي الحالية؟", "answer_html": "<p>افتح إعدادات الاشتراك لعرض الخطة المرتبطة حالياً بحسابك وتفاصيل الفوترة المتاحة هناك.</p>", "keywords": ["الخطة الحالية", "إعدادات الاشتراك", "تفاصيل الفوترة"]}, "fr": {"question": "Où puis-je voir mon forfait actuel ?", "answer_html": "<p>Ouvrez les paramètres d''abonnement pour consulter le forfait actuellement lié à votre compte ainsi que les détails de facturation disponibles.</p>", "keywords": ["forfait actuel", "paramètres abonnement", "détails facturation"]}, "ru": {"question": "Где посмотреть мой текущий тариф?", "answer_html": "<p>Откройте настройки подписки, чтобы увидеть тариф, подключенный к вашему аккаунту, и доступные там платежные детали.</p>", "keywords": ["текущий тариф", "настройки подписки", "платежные детали"]}}}, {"category_slug": "support-troubleshooting", "slug": "how-do-i-create-a-support-ticket", "sort_order": 10, "translations": {"en": {"question": "How do I create a support ticket?", "answer_html": "<p>Signed-in users can open /support/new to create a ticket. You can also review your existing ticket list from /support.</p>", "keywords": ["support ticket", "support new", "support list"]}, "ar": {"question": "كيف أنشئ تذكرة دعم؟", "answer_html": "<p>يمكن للمستخدمين المسجلين فتح /support/new لإنشاء تذكرة. كما يمكنك مراجعة قائمة التذاكر الحالية من /support.</p>", "keywords": ["تذكرة دعم", "دعم جديد", "قائمة الدعم"]}, "fr": {"question": "Comment créer un ticket de support ?", "answer_html": "<p>Les utilisateurs connectés peuvent ouvrir /support/new pour créer un ticket. Vous pouvez également consulter la liste de vos tickets depuis /support.</p>", "keywords": ["ticket support", "support new", "liste support"]}, "ru": {"question": "Как создать тикет поддержки?", "answer_html": "<p>Авторизованные пользователи могут открыть /support/new для создания тикета. Список текущих тикетов доступен на /support.</p>", "keywords": ["тикет поддержки", "support new", "список support"]}}}, {"category_slug": "support-troubleshooting", "slug": "can-i-attach-screenshots-or-pdfs", "sort_order": 20, "translations": {"en": {"question": "Can I attach screenshots or PDFs?", "answer_html": "<p>Yes. Support tickets can include private attachments such as screenshots or PDF files when they help explain the issue.</p>", "keywords": ["attachments", "screenshots", "pdf"]}, "ar": {"question": "هل يمكنني إرفاق لقطات شاشة أو ملفات PDF؟", "answer_html": "<p>نعم. يمكن أن تتضمن تذاكر الدعم مرفقات خاصة مثل لقطات الشاشة أو ملفات PDF عندما تساعد في شرح المشكلة.</p>", "keywords": ["مرفقات", "لقطات شاشة", "pdf"]}, "fr": {"question": "Puis-je joindre des captures d''écran ou des PDF ?", "answer_html": "<p>Oui. Les tickets de support peuvent inclure des pièces jointes privées comme des captures d''écran ou des fichiers PDF lorsqu''elles aident à expliquer le problème.</p>", "keywords": ["pièces jointes", "captures écran", "pdf"]}, "ru": {"question": "Можно ли прикреплять скриншоты или PDF?", "answer_html": "<p>Да. К тикетам поддержки можно прикреплять приватные вложения, например скриншоты или PDF, если они помогают объяснить проблему.</p>", "keywords": ["вложения", "скриншоты", "pdf"]}}}]'::jsonb AS data
)
INSERT INTO public.faq_item_translations (item_id, language_code, question, answer_html, keywords)
SELECT
  i.id,
  tr.key,
  COALESCE(tr.value ->> 'question', ''),
  COALESCE(tr.value ->> 'answer_html', ''),
  ARRAY(SELECT jsonb_array_elements_text(COALESCE(tr.value -> 'keywords', '[]'::jsonb)))
FROM item_seed
CROSS JOIN LATERAL jsonb_array_elements(item_seed.data) AS entry
CROSS JOIN LATERAL jsonb_each(entry -> 'translations') AS tr(key, value)
JOIN public.faq_items i ON i.slug = entry ->> 'slug'
ON CONFLICT (item_id, language_code) DO UPDATE
SET question = EXCLUDED.question,
    answer_html = EXCLUDED.answer_html,
    keywords = EXCLUDED.keywords;

UPDATE public.cms_pages
SET
  title = 'Frequently Asked Questions',
  content_html = '<p>Use this page to manage the SEO shell for the FAQ experience. The public FAQ questions and answers are loaded from the FAQ module.</p>',
  status = 'published',
  is_enabled = true,
  seo_title = 'Frequently Asked Questions | Smart Pocket',
  seo_description = 'Browse Smart Pocket FAQs about setup, transactions, budgets, subscriptions, support, and more.',
  seo_keywords = 'faqs,help,support,smart pocket',
  og_title = 'Smart Pocket FAQs',
  og_description = 'Find answers about Smart Pocket features, support, and everyday financial workflows.',
  twitter_title = 'Smart Pocket FAQs',
  twitter_description = 'Find answers about Smart Pocket features, support, and everyday financial workflows.',
  canonical_url_override = NULL,
  show_in_header = false,
  show_in_footer = false,
  navigation_label = 'FAQs',
  sort_order = 50,
  is_protected_system_page = true,
  allow_delete = false,
  published_at = COALESCE(published_at, CURRENT_TIMESTAMP),
  robots_index = true,
  robots_follow = true
WHERE LOWER(slug) = 'faqs';

INSERT INTO public.cms_pages (
  title,
  slug,
  content_html,
  status,
  is_enabled,
  seo_title,
  seo_description,
  seo_keywords,
  og_title,
  og_description,
  twitter_title,
  twitter_description,
  canonical_url_override,
  show_in_header,
  show_in_footer,
  navigation_label,
  sort_order,
  is_protected_system_page,
  allow_delete,
  published_at,
  robots_index,
  robots_follow
)
SELECT
  'Frequently Asked Questions',
  'faqs',
  '<p>Use this page to manage the SEO shell for the FAQ experience. The public FAQ questions and answers are loaded from the FAQ module.</p>',
  'published',
  true,
  'Frequently Asked Questions | Smart Pocket',
  'Browse Smart Pocket FAQs about setup, transactions, budgets, subscriptions, support, and more.',
  'faqs,help,support,smart pocket',
  'Smart Pocket FAQs',
  'Find answers about Smart Pocket features, support, and everyday financial workflows.',
  'Smart Pocket FAQs',
  'Find answers about Smart Pocket features, support, and everyday financial workflows.',
  NULL,
  false,
  false,
  'FAQs',
  50,
  true,
  false,
  CURRENT_TIMESTAMP,
  true,
  true
WHERE NOT EXISTS (
  SELECT 1
  FROM public.cms_pages existing
  WHERE LOWER(existing.slug) = 'faqs'
);

COMMIT;
